pub fn rotate_right<T: Clone>(arr: &mut [T], k: usize) {
    if arr.is_empty() {
        return;
    }

    let n = arr.len();
    let k = k % n;

    if k == 0 {
        return;
    }

    let mut temp = Vec::with_capacity(n);

    // Copy the last k elements
    for i in (n - k)..n {
        temp.push(arr[i].clone());
    }

    // Copy the first n-k elements
    for i in 0..(n - k) {
        temp.push(arr[i].clone());
    }

    // Copy back to original array
    for i in 0..n {
        arr[i] = temp[i].clone();
    }
}

