pub fn longest_common_prefix(strs: &[&str]) -> String {
    if strs.is_empty() {
        return String::new();
    }

    if strs.len() == 1 {
        return strs[0].to_string();
    }

    let mut prefix = String::new();
    let min_length = strs.iter().map(|s| s.len()).min().unwrap_or(0);

    for i in 0..min_length {
        let char_to_check = strs[0].chars().nth(i).unwrap();

        if strs.iter().all(|s| s.chars().nth(i).unwrap() == char_to_check) {
            prefix.push(char_to_check);
        } else {
            break;
        }
    }

    prefix
}

